	}
	// Ensure redirectPath starts with "/" to form a valid path
	if !strings.HasPrefix(redirectPath, "/") {
		redirectPath = "/" + redirectPath
	}
	fullRedirectURL := scheme + "://" + r.Host + redirectPath

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = fullRedirectURL

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state, oauth2.AccessTypeOnline)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   r.TLS != nil, // Use Secure flag only for HTTPS requests
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   3600, // Expire after 1 hour
	})

	return authURL, nil
}

