// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate redirectPath starts with /
	if !strings.HasPrefix(redirectPath, "/") {
		return "", errors.New("redirectPath must start with '/'")
	}

	// Determine scheme (http/https)
	scheme := "http"
	if r.TLS != nil {
		scheme = "https"
	}

	// Construct full redirect URL
	redirectURL := scheme + "://" + r.Host + redirectPath

	// Create a copy of OAuthConfig with custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectURL

	// Generate random state
	state, err := generateRandomState()
	if err != nil {
		return "", err
	}

	// Store state in session cookie
	if session == nil {
		session = &http.Cookie{
			Name:     "oauth_state",
			Value:    state,
			Path:     "/",
			Secure:   scheme == "https",
			HttpOnly: true,
			SameSite: http.SameSiteLaxMode,
			MaxAge:   300, // 5 minutes
		}
