	configCopy := *OAuthConfig
	originalRedirectURL, err := url.Parse(configCopy.RedirectURL)
	if err != nil {
		return "", err
	}
	originalRedirectURL.Path = strings.TrimRight(redirectPath, "/") // Ensure no trailing slash for consistency
	configCopy.RedirectURL = originalRedirectURL.String()

	// Generate the OAuth2 authorization URL with the state parameter
	authURL := configCopy.AuthCodeURL(state, oauth2.AccessTypeOnline)

	// Store state in session cookie for verification in callback
	if session == nil {
		session = &http.Cookie{}
	}
	session.Name = "oauth_state"
	session.Value = state
	session.HttpOnly = true
	session.Secure = strings.HasPrefix(configCopy.RedirectURL, "https://") // Use secure cookies for HTTPS
	session.Path = "/"
	session.MaxAge = 3600 // 1 hour expiry
	http.SetCookie(w, session)

	return authURL, nil
}

func generateRandomState() (string, error) {
	b := make([]byte, 32) // 32 bytes of randomness
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	// Encode to URL-safe base64 to make it suitable for URL parameters
	return base64.URLEncoding.EncodeToString(b), nil
}

// Example usage handler
func loginHandler(w http.ResponseWriter, r *http.Request) {
	sessionCookie, err := r.Cookie("oauth_state")
	if err != nil && !errors.Is(err, http.ErrNoCookie) {
